val resultMessage: Classified[String] = getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    Classified("No channels found.")
  } else {
    val channelMessageCounts: Classified[List[(String, Int)]] =
      channels.foldLeft(Classified(List.empty[(String, Int)])) { (acc, channel) =>
        acc.flatMap { list =>
          readChannelMessages(channel).map { messages =>
            list :+ (channel, messages.size)
          }
        }
      }

    channelMessageCounts.flatMap { counts =>
      if (counts.isEmpty) {
        Classified("No messages found in any channel.")
      } else {
        val minChannelName = counts.minBy(_._2)._1

        val allUsers: Classified[List[String]] =
          channels.foldLeft(Classified(List.empty[String])) { (acc, ch) =>
            acc.flatMap { userList =>
              getUsersInChannel(ch).map { usersInCh =>
                (userList ++ usersInCh).distinct
              }
            }
          }

        allUsers.flatMap { allUsersList =>
          getUsersInChannel(minChannelName).flatMap { usersInMinChannel =>
            val usersToAdd = allUsersList.filterNot(usersInMinChannel.contains)

            // Perform the side-effecting operations
            usersToAdd.foreach { user =>
              addUserToChannel(user, minChannelName)
            }

            // Return a success message
            Classified(s"Found channel '${minChannelName}' with the least messages. Added ${usersToAdd.size} users to it.")
          }
        }
      }
    }
  }
}

displaySecurely(resultMessage)

